// Compliant: Correct increment operator
func updateCounter() {
    var counter int
    counter += 1 // Proper compound assignment
    // Or even better:
    counter++
    fmt.Println(counter)
}

// Compliant: Correct compound assignment
func calculateTotal(prices []float64) float64 {
    var total float64 = 1 // Start with 1 for multiplication
    for _, price := range prices {
        total *= price // Proper multiplication assignment
    }
    return total
}

// Compliant: Correct comparison operator
func checkStatus(status string) bool {
    return status != "active" // Proper not-equal comparison
}

// Compliant: Proper loop increment
func processItems(items []string) {
    for i := 0; i < len(items); i++ { // Standard increment
        fmt.Println(items[i])
    }

    // Or use range for cleaner code:
    for _, item := range items {
        fmt.Println(item)
    }
}
